mapper.select:
SELECT S.MTRL_CD AS MTRL_CD, L.LOC_CD AS LOC_CD, L.LOC_NM AS LOC_NM, COALESCE(SUM(CAST(S.STOCK_QTY AS BIGINT)), 0) AS QTY FROM dbo.TBL_STOCK S INNER JOIN dbo.TBL_MTRL_M M ON S.CMPY_CD = M.CMPY_CD AND S.AGNT_CD = M.AGNT_CD AND S.MTRL_CD = M.MTRL_CD INNER JOIN dbo.TBL_WH_LOC_M L ON S.LOC_ID = L.LOC_ID
AND M.MTRL_CD = #{mtrlCd}
GROUP BY S.MTRL_CD, L.LOC_CD, L.LOC_NM ORDER BY L.LOC_CD

SELECT M.MTRL_CD AS MTRL_CD, M.MTRL_NM AS MTRL_NM, COALESCE(SUM(CAST(S.STOCK_QTY AS BIGINT)), 0) AS QTY FROM TBL_STOCK S INNER JOIN TBL_MTRL_M M ON S.CMPY_CD = M.CMPY_CD AND S.AGNT_CD = M.AGNT_CD AND S.MTRL_CD = M.MTRL_CD LEFT JOIN TBL_WH_LOC_M L ON S.LOC_ID = L.LOC_ID
AND S.LOC_ID = #{locId}
AND L.LOC_CD = #{locCd}
AND S.STOCK_QTY > 0
GROUP BY M.MTRL_CD, M.MTRL_NM ORDER BY M.MTRL_NM
